class _DashHandler(BaseHTTPRequestHandler):
    def log_message(self, *args):
        pass  # silence access logs

    def _send(self, code: int, ctype: str, body: bytes) -> None:
        self.send_response(code)
        self.send_header("Content-Type", ctype)
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def do_GET(self) -> None:
        if self.path == "/api/state":
            closed = [p for p in positions if p["status"] == "closed"]
            # iter-3.x: cumulative stats come from persisted counters
            # (survive reboot). In-session closed[] is still used for
            # the per-position table below.
            # Persisted counters are the source of truth — close_position
            # increments them on every close (paper + live). Fall back to
            # in-session tally only when both are zero (first run before
            # any close happened).
            if realized_pnl_today or wins_today or losses_today:
                total_pnl = realized_pnl_today
                wins = wins_today
                losses = losses_today
            else:
                total_pnl = sum(p.get("pnl_usd", 0) for p in closed)
                wins = sum(1 for p in closed if p.get("pnl_usd", 0) > 0)
                losses = len(closed) - wins
            # Add current_price + threshold prices for open positions so
            # the dashboard surfaces TP / SL / time-stop ETA explicitly.
            state_positions = []
            for p in positions:
                snap = dict(p)
                ep = float(p.get("entry_price") or 0)
                if ep > 0:
                    snap["tp_price"] = ep * (1 + TAKE_PROFIT_PCT / 100)
                    snap["sl_price"] = ep * (1 - STOP_LOSS_PCT / 100)
                if p["status"] == "open":
                    pd = oc.get_price_info(p["token"])
                    snap["current_price"] = _spot_from_price_response(pd)
                    # Time-stop: 12h from entry (matches the strategy spec).
                    entry_ts = p.get("entry_ts") or ""
                    try:
                        entry_dt = datetime.fromisoformat(entry_ts.replace("Z", "+00:00"))
                        time_stop_dt = (
                            entry_dt.replace(tzinfo=UTC) if entry_dt.tzinfo is None else entry_dt
                        )
                        from datetime import timedelta

                        time_stop_dt = time_stop_dt + timedelta(hours=12)
                        snap["time_stop_eta"] = time_stop_dt.isoformat()
                    except Exception:
                        snap["time_stop_eta"] = None
                state_positions.append(snap)
            payload = {
                "mode": "paper" if PAPER_TRADE else "live",
                "strategy": "jto_breakout_gecko_gated_contest",
                "entry_type": ENTRY_TYPE,
                "sl_pct": STOP_LOSS_PCT,
                "tp_pct": TAKE_PROFIT_PCT,
                "poll_sec": POLL_SEC,
                "wallet": WALLET_ADDRESS[:8] + "..." + WALLET_ADDRESS[-4:]
                if WALLET_ADDRESS
                else "",
                "positions": state_positions,
                "instruments": [
                    {
                        "symbol": inst["symbol"],
                        "mint": inst["mint"],
                        "chain": inst["chain"],
                        **(_LAST_SNAPSHOTS.get(inst["symbol"]) or {}),
                        "last_signal_check": _LAST_SIGNAL_CHECK.get(
                            inst["symbol"], {"breakout": False, "volume_spike": False}
                        ),
                    }
                    for inst in INSTRUMENTS
                ],
                "btc_overlay": {
                    "ok": _BTC_SNAPSHOT.get("ok"),
                    "reason": _BTC_SNAPSHOT.get("reason"),
                    "close": _BTC_SNAPSHOT.get("close"),
                    "ma": _BTC_SNAPSHOT.get("ma"),
                }
                if _BTC_SNAPSHOT
                else None,
                "signal_feed": signal_feed[-50:],
                "stats": {
                    "total_trades": (wins + losses) if (wins or losses) else len(closed),
                    "wins": wins,
                    "losses": losses,
                    "pnl_usd": round(total_pnl, 2),
                    "daily_trades": daily_trades,
                    "daily_limit": MAX_DAILY_TRADES,
                },
            }
            body = json.dumps(payload).encode()
            self._send(200, "application/json", body)
        else:
            body = DASHBOARD_HTML.encode()
            self._send(200, "text/html", body)


def _start_dashboard() -> None:
    srv = HTTPServer(("", DASHBOARD_PORT), _DashHandler)
    t = threading.Thread(target=srv.serve_forever, daemon=True)
    t.start()
    print(f"📊  Dashboard : http://localhost:{DASHBOARD_PORT}")


# ── Preflight ──────────────────────────────────────────────────────
def preflight() -> bool:
    global WALLET_ADDRESS
    status = oc.wallet_status()
    logged_in = status.get("loggedIn") or status.get("data", {}).get("loggedIn")
    if not logged_in:
        print("❌  Not logged in. Run: onchainos wallet login <email>")
        return False
    addr = oc.get_wallet_address()
    if not addr:
        print("❌  Could not resolve wallet address for chain:", CHAIN)
        return False
    WALLET_ADDRESS = addr
    balances = oc.get_all_balances()
    usdc_bal = next(
        (
            float(b.get("balanceUsd", 0) or 0)
            for b in balances
            if "USDC" in (b.get("symbol") or "").upper()
        ),
        0.0,
    )
    print(f"✅  Wallet : {WALLET_ADDRESS[:8]}...{WALLET_ADDRESS[-4:]}")
    print(f"✅  USDC   : ${usdc_bal:.2f}")
    if usdc_bal < USD_PER_TRADE:
        print(f"⚠️   Low balance: ${usdc_bal:.2f} — need ≥ ${USD_PER_TRADE} to trade")
    if not _usdc_address():
        print(f"⚠️   USDC address not mapped for chain {CHAIN} — live swaps will fail")
    return True


# ── Safety filters ─────────────────────────────────────────────────
def passes_safety(token: str) -> tuple[bool, list[str]]:
    """Run safety filters derived from the spec. Returns (passed, [failed_reasons])."""
    if not SAFETY:
        return True, []
    tags = oc.get_safety_tags(token)
    failed: list[str] = []
    if SAFETY.get("honeypot_check") and tags.honeypot:
        failed.append("HONEYPOT")
    if SAFETY.get("phishing_exclude") and tags.phishing_flagged:
        failed.append("PHISHING")
    if (v := SAFETY.get("lp_locked_min_pct")) and tags.lp_locked_pct < v:
        failed.append(f"LP lock {tags.lp_locked_pct:.0f}%<{v}%")
    if (v := SAFETY.get("buy_tax_max")) and tags.buy_tax_pct > v:
        failed.append(f"buy_tax {tags.buy_tax_pct:.1f}%>{v}%")
    if (v := SAFETY.get("sell_tax_max")) and tags.sell_tax_pct > v:
        failed.append(f"sell_tax {tags.sell_tax_pct:.1f}%>{v}%")
    if (v := SAFETY.get("liquidity_min_usd")) and tags.liquidity_usd < v:
        failed.append(f"liq ${tags.liquidity_usd:.0f}<${v}")
    if (v := SAFETY.get("top_holders_max_pct")) and tags.top_holders_pct > v:
        failed.append(f"top_holders {tags.top_holders_pct:.0f}%>{v}%")
    if (v := SAFETY.get("bundler_max_pct")) and tags.bundler_ratio_pct > v:
        failed.append(f"bundler {tags.bundler_ratio_pct:.0f}%>{v}%")
    if (v := SAFETY.get("dev_holding_max_pct")) and tags.dev_holding_pct > v:
        failed.append(f"dev_hold {tags.dev_holding_pct:.0f}%>{v}%")
    if (v := SAFETY.get("insider_max_pct")) and tags.insider_holding_pct > v:
        failed.append(f"insider {tags.insider_holding_pct:.0f}%>{v}%")
    if (v := SAFETY.get("whale_max_pct")) and tags.whale_max_pct > v:
        failed.append(f"whale {tags.whale_max_pct:.0f}%>{v}%")
    if (v := SAFETY.get("sm_present_min")) and tags.smart_money_count < v:
        failed.append(f"SM count {tags.smart_money_count}<{v}")
    if (v := SAFETY.get("mcap_min_usd")) and tags.mcap_usd < v:
        failed.append(f"mcap ${tags.mcap_usd:.0f}<${v}")
    if (v := SAFETY.get("mcap_max_usd")) and tags.mcap_usd > v:
        failed.append(f"mcap ${tags.mcap_usd:.0f}>${v}")
    return len(failed) == 0, failed


# ── Signal detection ───────────────────────────────────────────────
# Per-instrument kline snapshot, cached for the dashboard.
_LAST_SNAPSHOTS: dict[str, dict] = {}

# Per-instrument last-tick signal-fire booleans, surfaced via /api/state.
_LAST_SIGNAL_CHECK: dict[str, dict[str, bool]] = {}

# ── BTC overlay snapshot (poll-level cache) ────────────────────────
# We fetch BTC candles at most once per tick. The tuple is
# (epoch_ts_of_fetch, {ok, reason, close, ma}). poll_instruments()
# bumps the ts each tick; helper functions read the cached snapshot
# inside the same tick if called more than once.
_BTC_SNAPSHOT_TS: float = 0.0
_BTC_SNAPSHOT: dict[str, object] = {}
# Tick-id sentinel — bumped at the top of every poll_instruments().
# Cached snapshot is reused within a single tick; recomputed otherwise.
_BTC_CURRENT_TICK_ID: int = 0
_BTC_SNAPSHOT_TICK_ID: int = -1


def _median(vals: list[float]) -> float:
    if not vals:
        return 0.0
    s = sorted(vals)
    n = len(s)
    mid = n // 2
    if n % 2:
        return float(s[mid])
    return float((s[mid - 1] + s[mid]) / 2.0)


def btc_overlay_passes() -> tuple[bool, str]:
    """Poll-level BTC market filter. Returns (ok, reason).

    Cached per tick via ``_BTC_SNAPSHOT_TICK_ID``: even if called twice in
    the same tick we only fetch once. Fail-open on data error — we'd
    rather take a candidate during an onchainos hiccup than freeze all
    trading silently.
    """
    global _BTC_SNAPSHOT_TS, _BTC_SNAPSHOT, _BTC_SNAPSHOT_TICK_ID
    # iter-3.3 live 2026-05-20: BTC_OVERLAY = None disables the coarse
    # BTC safety belt. Voices remain the real gate (chart_analyst @ 0.85
    # floor + risk + memory). green_candle was binary-cruel on -0.05%
    # red bars during chop, blocking entries on statistical noise.
    if BTC_OVERLAY is None:
        snap = {"ok": True, "reason": "btc_overlay_disabled", "close": 0.0, "ma": 0.0}
        _BTC_SNAPSHOT = snap
        _BTC_SNAPSHOT_TS = time.time()
        _BTC_SNAPSHOT_TICK_ID = _BTC_CURRENT_TICK_ID
        return True, "btc_overlay_disabled"
    if _BTC_SNAPSHOT_TICK_ID == _BTC_CURRENT_TICK_ID and _BTC_SNAPSHOT:
        return bool(_BTC_SNAPSHOT["ok"]), str(_BTC_SNAPSHOT["reason"])

    ma_period = int(BTC_OVERLAY.get("ma_period", 20))
    condition = str(BTC_OVERLAY.get("condition", "above_ma"))

    try:
        candles = oc.get_candles(BTC_WBTC_MINT, "5m", limit=max(ma_period, 24))
    except Exception as exc:  # broad — never let an RPC blip halt the bot
        snap = {
            "ok": True,
            "reason": "btc_data_unavailable_fail_open",
            "close": None,
            "ma": None,
            "error": f"{type(exc).__name__}: {exc}",
        }
        _BTC_SNAPSHOT = snap
        _BTC_SNAPSHOT_TS = time.time()
        _BTC_SNAPSHOT_TICK_ID = _BTC_CURRENT_TICK_ID
        _log("warn", f"[BTC] data fetch raised {type(exc).__name__} — fail open")
        return True, "btc_data_unavailable_fail_open"

    if not candles or len(candles) < ma_period:
        snap = {
            "ok": True,
            "reason": "btc_data_unavailable_fail_open",
            "close": None,
            "ma": None,
        }
        _BTC_SNAPSHOT = snap
        _BTC_SNAPSHOT_TS = time.time()
        _BTC_SNAPSHOT_TICK_ID = _BTC_CURRENT_TICK_ID
        _log("warn", "[BTC] insufficient candle data — fail open")
        return True, "btc_data_unavailable_fail_open"

    closes = [float(c["close"]) for c in candles[-ma_period:]]
    ma = sum(closes) / len(closes)
    current_close = float(candles[-1]["close"])

    if condition == "above_ma":
        ok = current_close >= ma
        reason = "BTC above 20-MA" if ok else f"BTC below {ma_period}-MA"
    elif condition == "green_candle":
        last_open = float(candles[-1]["open"])
        ok = current_close > last_open
        delta_pct = (current_close - last_open) / last_open * 100 if last_open else 0.0
        reason = (
            f"BTC last bar green ({delta_pct:+.2f}%)"
            if ok
            else f"BTC last bar red ({delta_pct:+.2f}%)"
        )
    elif condition == "uptrend":
        # Heuristic: current close above its 8-bar EMA AND 8-bar EMA above
        # its lagged value 4 bars ago. Light, momentum-flavoured.
        if len(closes) < 12:
            ok = True
            reason = "uptrend_insufficient_data_fail_open"
        else:
            recent = closes[-8:]
            ema = recent[0]
            k = 2 / (8 + 1)
            for v in recent[1:]:
                ema = ema * (1 - k) + v * k
            lagged = sum(closes[-12:-4]) / 8
            ok = current_close > ema and ema > lagged
            reason = "BTC in uptrend" if ok else "BTC not in uptrend"
    else:
        # Default policy: unknown conditions pass through. Add support
        # explicitly when starter-coach surfaces new conditions.
        ok = True
        reason = f"unknown_condition_pass:{condition}"

    snap = {"ok": ok, "reason": reason, "close": current_close, "ma": ma}
    _BTC_SNAPSHOT = snap
    _BTC_SNAPSHOT_TS = time.time()
    _BTC_SNAPSHOT_TICK_ID = _BTC_CURRENT_TICK_ID
    return ok, reason


def evaluate_volume_spike(
    inst: dict, candles: list[dict] | None = None
) -> tuple[bool, dict | None]:
    """volume_spike entry primitive.

    Fires when ``volumes[-1] >= VOL_SPIKE_MULTIPLIER * median(volumes[-N:])``
    AND median > 0. The caller MAY pass pre-fetched candles to save a
    network round-trip; if omitted we refetch.
    """
    mint = inst["mint"]
    if candles is None:
        candles = oc.get_candles(mint, TIMEFRAME, limit=max(VOL_SPIKE_AVG_BARS + 1, 24))
    if not candles or len(candles) < 2:
        return False, None
    window = candles[-VOL_SPIKE_AVG_BARS:]
    vols = [float(c.get("volume", 0) or 0) for c in window]
    if not vols:
        return False, None
    last_vol = vols[-1]
    median_vol = _median(vols)
    if median_vol <= 0:
        return False, None
    ratio = last_vol / median_vol
    if last_vol >= VOL_SPIKE_MULTIPLIER * median_vol:
        return True, {
            "signal": "volume_spike",
            "instrument": inst["symbol"],
            "multiplier_observed": round(ratio, 3),
            "last_vol": last_vol,
            "median_vol": median_vol,
        }
    return False, None


def evaluate_breakout(inst: dict) -> dict | None:
    """Evaluate price_breakout on a single instrument's 5m klines.

    Returns a candidate dict ``{token, symbol, signal_data}`` if the
    latest close exceeds the prior ``lookback_bars`` highs by at least
    ``confirm_pct``%; otherwise ``None``. Always refreshes the
    dashboard snapshot for the instrument.
    """
    mint = inst["mint"]
    sym = inst["symbol"]
    lookback = int(ENTRY_PARAMS.get("lookback_bars", 4))
    confirm = float(ENTRY_PARAMS.get("confirm_pct", 0.2))

    candles = oc.get_candles(mint, TIMEFRAME, limit=max(lookback + 4, 24))
    price_data = oc.get_price_info(mint)
    spot = _spot_from_price_response(price_data)
    if spot == 0.0 and candles:
        spot = float(candles[-1].get("close") or 0)

    snap = {
        "symbol": sym,
        "mint": mint,
        "spot": spot,
        "bars": len(candles),
        "lookback": lookback,
        "confirm_pct": confirm,
        "delta_pct": None,
        "range_pct": None,
    }
    _LAST_SNAPSHOTS[sym] = snap

    if len(candles) < lookback + 1:
        return None

    # Most-recent candle is last in list per onchainos kline convention.
    recent = candles[-1]
    prior = candles[-(lookback + 1) : -1]
    if not prior:
        return None
    prior_high = max(c["high"] for c in prior)
    prior_low = min(c["low"] for c in prior)
    close = float(recent["close"])
    if prior_high <= 0 or close <= 0:
        return None

    delta_pct = (close - prior_high) / prior_high * 100.0
    range_pct = (prior_high - prior_low) / prior_low * 100.0 if prior_low > 0 else 0.0
    snap["delta_pct"] = round(delta_pct, 3)
    snap["range_pct"] = round(range_pct, 3)

    if delta_pct < confirm:
        return None

    _log(
        "info",
        f"[{sym}] entry signal: breakout up {delta_pct:.2f}% over {lookback} bars",
    )
    return {
        "token": mint,
        "symbol": f"{sym}-USDC",
        "signal_data": {
            "instrument": sym,
            "breakout_pct": round(delta_pct, 3),
            "range_pct": round(range_pct, 3),
            "lookback_bars": lookback,
            "spot_price": spot,
            "close": close,
            "prior_high": prior_high,
        },
    }


def poll_instruments() -> None:
    """Iterate INSTRUMENTS once per poll. MAX_CONCURRENT / daily_trades /
    total_spent_usd guards are checked PER ITERATION so a fill on JTO
    blocks JUP/PYTH in the same tick (global invariants).

    BTC overlay runs ONCE at the top of each tick. price_breakout and
    volume_spike fire in parallel with OR semantics — either firing
    produces a candidate. Voices grade what crosses the bar.
    """
    global _BTC_CURRENT_TICK_ID
    _BTC_CURRENT_TICK_ID += 1  # invalidate prior tick's BTC cache

    btc_ok, btc_reason = btc_overlay_passes()
    if not btc_ok:
        _log(
            "filter",
            f"[BTC] ✗ {btc_reason} — skipping all instruments this tick",
        )
        return

    for inst in INSTRUMENTS:
        # GLOBAL guards re-checked every instrument — a fill on the
        # previous iteration must block subsequent ones in this tick.
        if sum(1 for p in positions if p["status"] == "open") >= MAX_CONCURRENT:
            return
        if daily_trades >= MAX_DAILY_TRADES:
            return

        bo_cand = evaluate_breakout(inst)
        # Reuse the candles evaluate_breakout already fetched (via the
        # snapshot side-channel would be cleaner, but a single refetch
        # keeps the call sites independent and avoids hidden coupling
        # between primitives — onchainos has its own short cache).
        vs_fires, vs_signal = evaluate_volume_spike(inst)
        bo_fires = bo_cand is not None

        _LAST_SIGNAL_CHECK[inst["symbol"]] = {
            "breakout": bo_fires,
            "volume_spike": vs_fires,
        }

        if not (bo_fires or vs_fires):
            continue

        if bo_fires and vs_fires:
            primitive = "breakout+volume"
        elif bo_fires:
            primitive = "breakout"
        else:
            primitive = "volume_spike"

        # Build a unified signal_data carrying BOTH signal types if both fired.
        signal_data: dict = {"primitive": primitive, "instrument": inst["symbol"]}
        if bo_cand is not None:
            signal_data.update(bo_cand["signal_data"])
        if vs_signal is not None:
            signal_data.update(vs_signal)

        token = bo_cand["token"] if bo_cand else inst["mint"]
        symbol = bo_cand["symbol"] if bo_cand else f"{inst['symbol']}-USDC"

        ok, failed = passes_safety(token)
        if not ok:
            _log("filter", f"[{inst['symbol']}] ✗ safety: {', '.join(failed)}")
            continue

        _log("info", f"[{inst['symbol']}] ✓ candidate via {primitive}")
        open_position(token, symbol, signal_data)


# ── Position lifecycle ─────────────────────────────────────────────
def open_position(token: str, symbol_str: str, signal_data: dict) -> None:
    global daily_trades, total_spent_usd
    if daily_trades >= MAX_DAILY_TRADES:
        return
    if sum(1 for p in positions if p["status"] == "open") >= MAX_CONCURRENT:
        return
    if any(p["token"] == token and p["status"] == "open" for p in positions):
        return  # already in this token
    if not PAPER_TRADE and total_spent_usd + USD_PER_TRADE > MAX_BUDGET_USD:
        _log(
            "guard",
            f"[BUDGET CAP] ${total_spent_usd:.2f} spent — max budget ${MAX_BUDGET_USD} reached",
        )
        return

    price_data = oc.get_price_info(token)
    entry_price = _spot_from_price_response(price_data)
    if entry_price <= 0:
        print(f"[SKIP] No price for {symbol_str or token[:12]}")
        return

    # ── Gecko wrap: circuit-breaker check, then verdict-gated entry ──
    paused, reason = _BREAKER.check()
    if paused:
        _log("guard", f"[BREAKER] {reason}")
        _LOGGER.log("breaker_trip", {"token": token, "reason": reason})
        return

    instrument = symbol_str.split("-")[0] if symbol_str else token[:8]

    # Fetch fresh candles for chart_analyst — the voice's load-bearing
    # input. Without this, chart_analyst sees market_state["candles"]
    # as empty and abstains with "Fewer than 24 bars provided" — which
    # silently bottlenecks every panel decision into chart_below_threshold.
    # ~50ms call; only fires on candidate entries (not every poll).
    try:
        ms_candles = oc.get_candles(token, TIMEFRAME, limit=30)
    except Exception as exc:
        print(f"[market_state] candle fetch failed for {symbol_str}: {exc}")
        ms_candles = []

    # Compute deltas + range from the fresh candles. The signal_data dict
    # doesn't carry these (evaluate_breakout / evaluate_volume_spike don't
    # populate priceChange24h / range24h / volume24h), so reading from it
    # always returned 0.0 — chart_analyst then read "range 0.00%" and
    # abstained as "range-bound chop." Compute authoritatively from candles.
    chg_24h, chg_1h, range_24h, vol_total = 0.0, 0.0, 0.0, 0.0
    if ms_candles and len(ms_candles) >= 2:
        closes = [float(c.get("close") or c.get("c") or 0) for c in ms_candles]
        highs = [float(c.get("high") or c.get("h") or 0) for c in ms_candles]
        lows = [float(c.get("low") or c.get("l") or 0) for c in ms_candles]
        vols = [float(c.get("volume") or c.get("vol") or 0) for c in ms_candles]
        anchor = closes[0] if closes and closes[0] > 0 else 0
        spot_close = closes[-1] if closes else 0
        if anchor > 0:
            chg_24h = (spot_close - anchor) / anchor * 100
            range_24h = (max(highs) - min(lows)) / anchor * 100
        if len(closes) >= 12 and closes[-12] > 0:
            chg_1h = (spot_close - closes[-12]) / closes[-12] * 100
        vol_total = sum(vols)

    market_state = {
        "instrument": instrument,
        "spot_price": entry_price,
        "change_24h_pct": chg_24h,
        "change_1h_pct": chg_1h,
        "range_24h_pct": range_24h,
        "volume_24h": vol_total,
        # chart_analyst input — the actual OHLCV bars the voice grades.
        "candles": ms_candles,
        # risk_voice deterministic-only context (post-2026-05-20 patch):
        "open_positions": sum(1 for p in positions if p["status"] == "open"),
        "daily_trades": daily_trades,
        "total_spent_usd": total_spent_usd,
        "hourly_pnl_delta": 0.0,
        "max_daily_trades": MAX_DAILY_TRADES,
        "max_budget_usd": MAX_BUDGET_USD,
    }

    # ── Local-lab panel (runs BEFORE the Gecko shadow gate) ─────────
    # Lazy `is not None` lets the bot run before ai-ml-engineer's
    # voices land. Once they do, a voice-bootstrap module wires the
    # panel in and this branch starts firing. The local panel is
    # advisory + observed via local_memory.jsonl; the Gecko shadow
    # gate still runs below and is the only thing that touches the
    # artifact-log ledger surface.
    if _LOCAL_PANEL is not None:
        local_decision = asyncio.run(_LOCAL_PANEL.run(market_state))
        _LOGGER.log(
            "local_panel",
            {
                "instrument": instrument,
                "action": local_decision.action,
                "reason": local_decision.reason,
                "coordinator_rule_fired": local_decision.coordinator_rule_fired,
                "voice_count": len(local_decision.voice_opinions),
                "total_elapsed_ms": local_decision.total_elapsed_ms,
                "total_cost_usd": local_decision.total_cost_usd,
            },
            decision_id=local_decision.decision_id,
        )
        if local_decision.action != "act":
            _log("filter", f"[LOCAL] ✗ {local_decision.reason}")
            return

    # ── Fundamentals oracle: cached PRD verdict lookup (s40-lab-#7) ──
    # Informational only — NEVER gates the trade. Local panel above has
    # already decided. The fundamentals side-note is logged so the
    # artifact ledger carries a slow value-investor read alongside the
    # local fast TA decision. Cache may be empty (preload failed,
    # degraded mode, or instrument unknown) — that's fine, we proceed.
    fund_verdict = _FUNDAMENTALS.get_for_instrument(instrument)
    fund_decision_id: str | None = None
    if fund_verdict is not None:
        cache_age_s = (datetime.now(UTC) - fund_verdict.ts).total_seconds()
        fund_decision_id = _LOGGER.log(
            "fundamentals_check",
            {
                "instrument": instrument,
                "verdict": fund_verdict.verdict,
                "confidence": fund_verdict.confidence,
                "key_drivers": fund_verdict.key_drivers,
                "blocker_questions": fund_verdict.blocker_questions,
                "citations_count": fund_verdict.citations_count,
                "cache_age_s": cache_age_s,
                "protocol": fund_verdict.protocol,
            },
            decision_id=local_decision.decision_id if _LOCAL_PANEL is not None else None,
        )
        _log(
            "info",
            f"[FUND] {instrument}: {fund_verdict.verdict}@{fund_verdict.confidence:.2f} "
            f"({fund_verdict.citations_count} cites, age {cache_age_s / 60:.0f}m)",
        )
    else:
        _log("info", f"[FUND] {instrument}: no cached verdict (degraded)")

    ts = datetime.utcnow().isoformat()
    pos = {
        "token": token,
        "symbol": symbol_str,
        "entry_price": entry_price,
        "usd": USD_PER_TRADE,
        "entry_ts": ts,
        "status": "open",
        "peak_price": entry_price,
        "signal_data": signal_data,
        "mode": "paper",
        "fundamentals_decision_id": fund_decision_id,
    }

    if PAPER_TRADE:
        _log(
            "buy",
            f"[PAPER] BUY {symbol_str or token[:12]} @ ${entry_price:.6f} | ${USD_PER_TRADE} | SL -{STOP_LOSS_PCT}%",
        )
    else:
        usdc = _usdc_address()
        if not usdc:
            _log("error", f"[ERROR] USDC address not mapped for {CHAIN}")
            return
        result = oc.swap_execute(usdc, token, str(USD_PER_TRADE), WALLET_ADDRESS)
        if not result.ok:
            _log("error", f"[ERROR] Swap failed: {result.error}")
            return
        pos["mode"] = "live"
        pos["tx_hash"] = result.tx_hash
        total_spent_usd += USD_PER_TRADE
        _log(
            "buy",
            f"[LIVE] BUY {symbol_str} @ ${entry_price:.6f} | tx: {result.tx_hash[:16]}... | total spent ${total_spent_usd:.2f}/${MAX_BUDGET_USD}",
        )

    positions.append(pos)
    daily_trades += 1
    _LOGGER.log(
        "position_open",
        {
            "token": token,
            "symbol": symbol_str,
            "entry_price": entry_price,
            "usd": USD_PER_TRADE,
            "mode": pos["mode"],
        },
        decision_id=fund_decision_id,
    )
    _persist_state()


def close_position(pos: dict, reason: str, current_price: float) -> None:
    global consec_losses, realized_pnl_today, wins_today, losses_today, total_spent_usd
    ep = pos["entry_price"]
    cost_usd = float(pos.get("usd") or 0)
    # Oracle-price estimate — used for PAPER mode and as a pre-swap log hint.
    est_pnl_pct = (current_price - ep) / ep * 100 if ep else 0.0
    est_pnl_usd = cost_usd * est_pnl_pct / 100

    # iter-3.7 live 2026-05-20: for LIVE positions, execute the exit swap
    # FIRST and compute realized PnL from the ACTUAL USDC received
    # (swap.to_amount_raw), not the oracle price. The oracle can flash a
    # spiky tick (WIF flashed +6.2% but really filled +0.45%); booking the
    # oracle reading inflated dashboard PnL ~3.5x vs the real wallet.
    pnl_usd = est_pnl_usd
    pnl_pct = est_pnl_pct
    exit_tx = ""
    if not PAPER_TRADE and pos.get("mode") == "live":
        usdc = _usdc_address()
        bal = oc.get_token_balance(pos["token"])
        if bal > 0 and usdc:
            result = oc.swap_execute(pos["token"], usdc, str(bal), WALLET_ADDRESS)
            if result.ok:
                exit_tx = result.tx_hash
                # Real USDC received = to_amount_raw / 10^to_decimals.
                try:
                    if result.to_amount_raw and result.to_decimals:
                        usdc_received = float(result.to_amount_raw) / (10 ** result.to_decimals)
                        pnl_usd = round(usdc_received - cost_usd, 4)
                        pnl_pct = round(pnl_usd / cost_usd * 100, 2) if cost_usd else 0.0
                    else:
                        # Swap ok but no amount returned — fall back to oracle
                        # estimate and flag it for the audit log.
                        print("   [WARN] swap ok but to_amount missing — using oracle estimate")
                except (TypeError, ValueError, ZeroDivisionError):
                    print("   [WARN] could not parse swap fill — using oracle estimate")
                print(f"   exit tx: {exit_tx[:16]}... | real fill PnL ${pnl_usd:+.2f}")
            else:
                # Exit swap FAILED — do NOT mark the position closed. Leave it
                # open so the next monitor tick retries. Booking a close here
                # would strand the token in the wallet (the PYTH bug).
                print(f"   [ERROR] Exit swap failed: {result.error} — position stays OPEN for retry")
                return

    pos.update(
        {
            "status": "closed",
            "exit_ts": datetime.utcnow().isoformat(),
            "exit_price": current_price,
            "exit_reason": reason,
            "pnl_pct": round(pnl_pct, 2),
            "pnl_usd": round(pnl_usd, 2),
            "exit_tx": exit_tx,
        }
    )
    consec_losses = consec_losses + 1 if pnl_pct < 0 else 0
    # iter-3.x 2026-05-20: accumulate into persisted counters so the
    # dashboard PnL tile survives a bot reboot.
    realized_pnl_today = round(realized_pnl_today + pnl_usd, 4)
    if pnl_usd > 0:
        wins_today += 1
    elif pnl_usd < 0:
        losses_today += 1
    # iter-3.7: free the budget the closed position was holding so new
    # entries can fire (was the stuck-at-$90 budget-cap bug).
    if pos.get("mode") == "live":
        total_spent_usd = round(max(0.0, total_spent_usd - cost_usd), 4)
    icon = "📗" if pnl_pct >= 0 else "📕"
    _log(
        "sell",
        f"{icon} CLOSE {pos['symbol'] or pos['token'][:12]} | {reason} | {pnl_pct:+.1f}% | ${pnl_usd:+.2f}",
    )

    # ── Gecko wrap: feed realized PnL into the breaker + ledger ─────
    _BREAKER.record_pnl_delta(float(pnl_usd))
    _LOGGER.log(
        "position_close",
        {
            "token": pos["token"],
            "symbol": pos.get("symbol"),
            "exit_reason": reason,
            "pnl_pct": round(pnl_pct, 2),
            "pnl_usd": round(pnl_usd, 2),
            "exit_tx": exit_tx,
        },
        decision_id=pos.get("gate_decision_id"),
    )
    _persist_state()


# ── Per-poll telemetry (iter-3.8, 2026-05-21) ──────────────────────
# Append one row per open position per poll to poll_telemetry_YYYYMMDD.jsonl.
# This is the DATA FOUNDATION for the data-driven stall detector (v2): the
# quant flagged that we currently store no per-poll price series, so no stall
# threshold can ever be validated. Schema maps 1:1 to a future Mongo
# collection (lab-first, transplant to PRD per local_lab_strategy). The
# return-series alone supports the highest-merit v2 signal (autocorrelation
# of returns: mean-reverting ⇒ stall, persistent ⇒ pause) — no volume needed.
_TELEMETRY_PATH = Path(__file__).parent / f"poll_telemetry_{datetime.now(UTC).strftime('%Y%m%d')}.jsonl"


def _log_telemetry(row: dict) -> None:
    """Best-effort append of a per-poll telemetry row. Never raises into the
    poll loop — telemetry failure must not halt trading."""
    try:
        with open(_TELEMETRY_PATH, "a", encoding="utf-8") as f:
            f.write(json.dumps(row) + "\n")
    except OSError:
        pass


def _mins_since(ts_iso: str, default: float = 0.0) -> float:
    """Minutes elapsed since an ISO-UTC timestamp. Tolerant of naive/aware."""
    try:
        dt = datetime.fromisoformat(ts_iso.replace("Z", "+00:00"))
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=UTC)
        return (datetime.now(UTC) - dt).total_seconds() / 60
    except Exception:
        return default


# ── Monitor open positions ─────────────────────────────────────────
def monitor_positions() -> None:
    for pos in [p for p in positions if p["status"] == "open"]:
        price_data = oc.get_price_info(pos["token"])
        current_price = _spot_from_price_response(price_data)
        if not current_price:
            continue

        # Track last new-high time BEFORE updating peak, so we can tell
        # whether THIS poll set a new high (used by the flat-stall gate).
        prev_peak = pos.get("peak_price", 0)
        now_iso = datetime.now(UTC).isoformat()
        if current_price >= prev_peak:
            pos["last_new_high_ts"] = now_iso
        elif "last_new_high_ts" not in pos:
            # Positions recovered from state pre-iter-3.8 won't have it —
            # seed from entry so the no-new-high timer starts at entry.
            pos["last_new_high_ts"] = pos.get("entry_ts", now_iso)

        pos["peak_price"] = max(prev_peak, current_price)
        ep = pos["entry_price"]
        pnl_pct = (current_price - ep) / ep * 100 if ep else 0.0
        peak_pct = (pos["peak_price"] - ep) / ep * 100 if ep else 0.0
        mins_since_high = _mins_since(pos["last_new_high_ts"])

        # Telemetry — one row per position per poll (data foundation for v2).
        _log_telemetry(
            {
                "ts": now_iso,
                "symbol": pos.get("symbol"),
                "token": pos.get("token"),
                "price": current_price,
                "entry_price": ep,
                "pnl_pct": round(pnl_pct, 4),
                "peak_pct": round(peak_pct, 4),
                "mins_since_high": round(mins_since_high, 2),
                "age_min": round(_mins_since(pos.get("entry_ts", now_iso)), 2),
                "mode": pos.get("mode"),
            }
        )

        # Trailing stop with activate_after_pct gate (iter-3 2026-05-20):
        # Trail only fires AFTER position has been >= TRAIL_ACTIVATE_AFTER_PCT
        # green from entry. This prevents trail from closing positions that
        # only briefly touched green — letting real winners ride toward TP
        # before the trail engages. MEW (peak +0.06%) and PYTH (peak +1.93%)
        # would NOT have triggered trail under iter-3.
        if TRAIL_STOP_PCT is not None:
            peak = pos["peak_price"]
            peak_pct = (peak - ep) / ep * 100 if ep else 0.0
            if peak_pct >= TRAIL_ACTIVATE_AFTER_PCT:
                trail = (peak - current_price) / peak * 100 if peak else 0.0
                if trail >= TRAIL_STOP_PCT:
                    close_position(pos, "trailing_stop", current_price)
                    continue

        # Stop loss
        if pnl_pct <= -STOP_LOSS_PCT:
            close_position(pos, "stop_loss", current_price)
            continue

        # Tiered take profit

        # Flat take profit
        if pnl_pct >= TAKE_PROFIT_PCT:
            close_position(pos, "take_profit", current_price)
            continue

        # iter-3.5 stall-green exit (founder rule, 2026-05-20):
        # If position has been open ≥60min AND is green by ≥2%, book the win
        # rather than waiting indefinitely for TP. Catches the modal failure
        # mode where price drifts to +2-3% then stalls — neither trail (no
        # retracement) nor TP (never hits 4%) fire, and the position bleeds
        # the 12h time-stop near $0.
        entry_ts_iso = pos.get("entry_ts", "")
        try:
            entry_dt = datetime.fromisoformat(entry_ts_iso.replace("Z", "+00:00"))
            if entry_dt.tzinfo is None:
                entry_dt = entry_dt.replace(tzinfo=UTC)
            age_min = (datetime.now(UTC) - entry_dt).total_seconds() / 60
        except Exception:
            age_min = 0.0
        if age_min >= STALL_GREEN_EXIT_AGE_MIN and pnl_pct >= STALL_GREEN_EXIT_MIN_PCT:
            close_position(pos, "stall_green_exit", current_price)
            continue

        # iter-3.8 flat-stall exit (see constants block). Catches the BONK
        # no-man's-land BELOW the +2% stall_green_exit threshold: aged,
        # stuck in the +0.3-2% band, and no new high in 30min (= momentum
        # spent, not consolidating). Locks the small green before it drifts
        # to a flat/negative 12h time-stop.
        if (
            age_min >= FLAT_STALL_AGE_MIN
            and FLAT_STALL_PNL_LO <= pnl_pct <= FLAT_STALL_PNL_HI
            and mins_since_high >= FLAT_STALL_NO_NEW_HIGH_MIN
        ):
            close_position(pos, "flat_stall_exit", current_price)
            continue

        print(
            f"[POS] {pos['symbol'] or pos['token'][:12]} | ${ep:.6f} → ${current_price:.6f} | {pnl_pct:+.1f}%"
        )


# ── Risk guards ────────────────────────────────────────────────────
def reset_daily() -> None:
    global daily_trades, last_reset_day
    today = datetime.utcnow().strftime("%Y-%m-%d")
    if today != last_reset_day:
        daily_trades = 0
        last_reset_day = today
        _persist_state()


def should_pause() -> bool:
    if consec_losses >= SESSION_LOSS_PAUSE:
        print(f"[PAUSE] {consec_losses} consecutive losses — sitting out this session")
        return True
    return False


# ── Main loop ──────────────────────────────────────────────────────
def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument(
        "--smoke-test", action="store_true", help="Verify dashboard endpoints then exit"
    )
    ap.add_argument(
        "--rebuild-state",
        action="store_true",
        help="Force rebuild of bot_state from today's artifact log (bypasses bot_state.json).",
    )
    args = ap.parse_args()

    print(f"""
╔══════════════════════════════════════╗
║  My Strategy                          ║
║                                       ║
╠══════════════════════════════════════╣
║  Mode   : {"PAPER 📄" if PAPER_TRADE else "LIVE  🔴":<29} ║
║  Entry  : {ENTRY_TYPE:<29} ║
║  SL -{STOP_LOSS_PCT}%  TP +{TAKE_PROFIT_PCT}%                      ║
╚══════════════════════════════════════╝
""")

    if args.smoke_test:
        import urllib.request as _ureq

        _start_dashboard()
        time.sleep(1.5)
        try:
            r1 = _ureq.urlopen(f"http://localhost:{DASHBOARD_PORT}/", timeout=4)
            assert r1.status == 200, f"/ returned {r1.status}"
            r2 = _ureq.urlopen(f"http://localhost:{DASHBOARD_PORT}/api/state", timeout=4)
            assert r2.status == 200, f"/api/state returned {r2.status}"
            json.loads(r2.read())  # must be valid JSON
            print("SMOKE_TEST_OK")
            sys.exit(0)
        except Exception as e:
            print(f"SMOKE_TEST_FAIL: {e}")
            sys.exit(1)

    if not preflight():
        sys.exit(1)

    # ── Live mode gate ─────────────────────────────────────────────
    if not PAPER_TRADE:
        print("\n" + "=" * 50)
        print("🔴  LIVE MODE — REAL FUNDS AT RISK")
        print("=" * 50)
        print("  Strategy   : My Strategy")
        print(f"  Per trade  : ${25} USD")
        print(f"  Budget cap : ${MAX_BUDGET_USD} USD")
        print(f"  Stop loss  : -{STOP_LOSS_PCT}%")
        print("\nReal money will be used. Losses are permanent.")
        print("Safety filters do not guarantee protection against all fraud.")
        print("Automated trading may generate significant taxable events.")
        print("\nType CONFIRM to proceed, or press Ctrl+C to cancel:\n")
        try:
            user_input = input("> ").strip()
        except (KeyboardInterrupt, EOFError):
            print("\nCancelled. Run with PAPER_TRADE = True to test first.")
            sys.exit(0)
        if user_input.upper() != "CONFIRM":
            print("\nLive mode not activated. Set PAPER_TRADE = True to run in paper mode.")
            sys.exit(0)
        # Log acknowledgment
        import json as _json
        from pathlib import Path as _P

        _ack = {
            "ts": datetime.utcnow().isoformat(),
            "strategy": "jto_breakout_gecko_gated_contest",
            "confirmation": "CONFIRM",
            "budget_cap": MAX_BUDGET_USD,
        }
        _ack_path = _P(__file__).parent / "jto_breakout_gecko_gated_contest_live_ack.jsonl"
        with open(_ack_path, "a") as _f:
            _f.write(_json.dumps(_ack) + "\n")
        print("\n✅ Live mode confirmed. Starting bot...\n")

    _start_dashboard()

    # ── Fundamentals preload (s40-lab-#7) ──────────────────────────
    # Fire ~80-100s of parallel PRD calls before the trade loop starts.
    # Failures degrade gracefully — bot still runs without the cached
    # side notes. SKIP if the env var is set (smoke tests, dev runs).
    if not os.environ.get("GECKO_FUND_PRELOAD_SKIP"):
        print(
            f"[fundamentals] preloading verdicts for {len(INSTRUMENTS)} "
            f"instruments (parallel, ~80-100s)..."
        )
        try:
            _cache = asyncio.run(_FUNDAMENTALS.preload_for_instruments(INSTRUMENTS))
            print(f"[fundamentals] preloaded {len(_cache)} verdicts")
            for _sym, _v in _cache.items():
                print(f"  {_sym:6s}: {_v.verdict}@{_v.confidence:.2f}  {_v.citations_count} cites")
        except Exception as _exc:
            print(f"[fundamentals] preload failed (degraded mode): {_exc}")
    else:
        print("[fundamentals] preload skipped (GECKO_FUND_PRELOAD_SKIP set)")

    print(f"Scanning every {POLL_SEC}s — Ctrl+C to stop\n")

    try:
        while True:
            reset_daily()
            if should_pause():
                time.sleep(POLL_SEC * 2)
                continue

            monitor_positions()
            poll_instruments()
            time.sleep(POLL_SEC)

    except KeyboardInterrupt:
        closed = [p for p in positions if p["status"] == "closed"]
        open_pos = sum(1 for p in positions if p["status"] == "open")
        total_pnl = sum(p.get("pnl_usd", 0) for p in closed)
        wins = sum(1 for p in closed if p.get("pnl_usd", 0) > 0)
        print("\n👋 Bot stopped.")
        print(f"   {len(closed)} trades | {wins}W / {len(closed) - wins}L | PnL: ${total_pnl:+.2f}")
        if open_pos:
            print(f"   ⚠️  {open_pos} position(s) still open — close manually if live")


if __name__ == "__main__":
    main()
